function Anim({ children, delay = 0 }) {
  const ref = useRef(null);
  const [v, setV] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.08 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return <div ref={ref} style={{ opacity:v?1:0, transform:v?"translateY(0)":"translateY(22px)", transition:`all 0.6s cubic-bezier(0.16,1,0.3,1) ${delay}ms` }}>{children}</div>;
}

function Chip({ children }) {
  return <span style={{ fontFamily:C.mono,fontSize:11,padding:"4px 10px",borderRadius:4,background:C.accentDim,color:C.accent,border:`1px solid ${C.accentMid}` }}>{children}</span>;
}

function TechPill({ name }) {
  const logo = techLogos[name];
  return <span style={{ display:"inline-flex",alignItems:"center",gap:6,fontSize:11,fontWeight:500,padding:"3px 8px",borderRadius:4,background:C.bg,color:C.muted,border:`1px solid ${C.border}` }}>{logo&&<img src={logo} alt="" width="12" height="12" style={{borderRadius:2}}/>}{name}</span>;
}

function Arrow({ open }) {
  return <span style={{ display:"inline-block",transition:"transform 0.3s",transform:open?"rotate(90deg)":"rotate(0deg)",color:C.accent,fontSize:13 }}>▸</span>;
}

function Toggle({ label, open, onClick, children }) {
  return <>
    <button onClick={onClick} style={{ background:"none",border:"none",cursor:"pointer",display:"flex",alignItems:"center",gap:6,color:C.accent,fontSize:13,fontFamily:C.mono,padding:"6px 0" }}>
      <Arrow open={open}/> {open?"Collapse details":label}
    </button>
    <div style={{ maxHeight:open?"6000px":"0px",overflow:"hidden",transition:"max-height 0.5s cubic-bezier(0.4,0,0.2,1)" }}>
      <div style={{ paddingTop:14,borderTop:`1px solid ${C.border}`,marginTop:10 }}>{children}</div>
    </div>
  </>;
}

function DetailList({ items }) {
  return <div style={{ display:"flex",flexDirection:"column",gap:10 }}>{items.map((item,i)=>(<div key={i} style={{ fontSize:13.5,color:C.text,paddingLeft:16,position:"relative",lineHeight:1.7 }}><span style={{ position:"absolute",left:0,color:C.accent,fontSize:12 }}>›</span>{item}</div>))}</div>;
}

function LinkBtn({ href, label, icon }) {
  return <a href={href} target="_blank" rel="noreferrer" onClick={e=>e.stopPropagation()} style={{ display:"inline-flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:6,background:C.accentDim,border:`1px solid ${C.accentMid}`,color:C.accent,fontSize:12,fontFamily:C.mono }}>{icon} {label} <span style={{fontSize:11,opacity:0.6}}>↗</span></a>;
}

